import type { NextRequest } from 'next/server'
import { createHash, timingSafeEqual } from 'crypto'

type CronRequest = Request | NextRequest

export type CronAuthResult = {
  authorized: boolean
  reason?: string
}

function secureEquals(left: string, right: string): boolean {
  const leftDigest = createHash('sha256').update(left).digest()
  const rightDigest = createHash('sha256').update(right).digest()
  return timingSafeEqual(leftDigest, rightDigest)
}

function headerEquals(header: string | null, value: string | undefined) {
  if (!header || !value) return false
  return secureEquals(header.trim(), value)
}

export function authorizeCronRequest(request: CronRequest): CronAuthResult {
  const cronSecret = process.env.CRON_SECRET?.trim()
  const authHeader = request.headers.get('authorization')?.trim() ?? null
  const vercelCronHeader = request.headers.get('x-vercel-cron')
  const isVercelCronHeaderPresent = vercelCronHeader === '1'

  if (!cronSecret) {
    if (process.env.NODE_ENV !== 'production') {
      // In non-production environments allow cron execution without auth for convenience
      return { authorized: true }
    }

    return {
      authorized: false,
      reason: 'CRON_SECRET is required in production'
    }
  }

  const bearerSecret = `Bearer ${cronSecret}`
  if (headerEquals(authHeader, bearerSecret) || headerEquals(authHeader, cronSecret)) {
    return { authorized: true }
  }

  // Keep this signal for diagnostics only; it is not trusted for auth by itself.
  if (isVercelCronHeaderPresent) {
    return {
      authorized: false,
      reason: 'Vercel cron header present but authorization secret is invalid or missing'
    }
  }

  return {
    authorized: false,
    reason: 'Missing or invalid cron credentials'
  }
}

Signature line to copy: `export function authorizeCronRequest(request: Request | NextRequest): CronAuthResult` where `CronAuthResult = { authorized: boolean; reason?: string }`. It is SYNCHRONOUS (not async) — call it as `const authResult = authorizeCronRequest(request)` with no await. It accepts both `Bearer <CRON_SECRET>` and a bare `<CRON_SECRET>` authorization header, compares in constant time via SHA-256 + timingSafeEqual, treats the `x-vercel-cron: 1` header as diagnostic only (never trusted for auth), and short-circuits to authorized in non-production when CRON_SECRET is unset.

Standard call site pattern (from both example routes):

  const authResult = authorizeCronRequest(request);
  if (!authResult.authorized) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

(The event-checklist-reminders route uses the same call but names it `auth` and returns `new NextResponse('Unauthorized', { status: 401 })`.)

The London-time gate uses `date-fns-tz`. Import and constant:

  import { toZonedTime, format, formatInTimeZone } from 'date-fns-tz';  // rota-staff-email
  import { toZonedTime, format, fromZonedTime } from 'date-fns-tz';     // rota-auto-close
  const TIMEZONE = 'Europe/London';

Step 1 — convert current UTC instant to a London-wall-clock Date:

  const nowUtc = new Date();
  const nowLocal = toZonedTime(nowUtc, TIMEZONE);

`toZonedTime(nowUtc, 'Europe/London')` returns a Date whose local getters (`getDay()`, `getHours()`, etc.) read as London wall-clock time, regardless of the server's own timezone (Vercel runs UTC).

Step 2 — gate on the London wall-clock fields:

  // Day-of-week gate (rota-staff-email): only run on Sunday
  if (nowLocal.getDay() !== 0) {
    return NextResponse.json({ skipped: true, reason: 'Not Sunday' });
  }

  // Hour-of-day gate (rota-auto-close): DST-tolerant 04:00–06:00 London window
  const localHour = nowLocal.getHours();
  if (localHour < 4 || localHour > 6) {
    return NextResponse.json({
      skipped: true,
      reason: `Local hour ${localHour} is outside expected window`,
      localTime: format(nowLocal, 'HH:mm zzz', { timeZone: TIMEZONE }),
    });
  }

Step 3 — echo the London time in the response for diagnostics:

  localTime: format(nowLocal, 'HH:mm zzz', { timeZone: TIMEZONE }),

Other date-fns-tz helpers used for London math in these files:
- `formatInTimeZone(nextMon, TIMEZONE, 'yyyy-MM-dd')` — format a UTC Date directly as a London-zoned ISO date string (rota-staff-email's getNextMondayIso).
- `fromZonedTime(`${endDate}T${endClock}:00`, TIMEZONE)` — the inverse of toZonedTime: interpret a London wall-clock string and return the correct UTC instant (rota-auto-close, when building clock-out timestamps from scheduled shift end / 23:59 local fallback).

Why the in-code gate exists: vercel.json schedules are UTC, so a `"0 5 * * *"` cron fires at 05:00 UTC which is 05:00 or 06:00 London depending on BST/GMT; the toZonedTime hour-window re-check makes the job DST-correct. Routes that need only 'today in London' (e.g. event-checklist-reminders) instead call `getTodayIsoDate()` from '@/lib/dateUtils', which is the project's London-hardcoded helper — prefer that over raw date-fns-tz when you just need the London ISO date.

